const axios = require('axios');
const SUPABASE_URL = 'https://vpmwizzixnwilmzctdvu.supabase.co';
const SUPABASE_KEY = (typeof process !== 'undefined' && process.env && process.env.SUPABASE_SERVICE_KEY) || 'sb_secret_EXq938yU-MinIxdpOc0nZg_qL-N3BCq';
const PAGE_SIZE = 1000;
let all = [];
let offset = 0;
while (true) {
  const resp = await axios.get(
    `${SUPABASE_URL}/rest/v1/orders?select=order_id,appointment_at,final_sale_price,total_cost,net_profit&deleted_at=is.null&order=id.asc&limit=${PAGE_SIZE}&offset=${offset}`,
    { headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` }, timeout: 15000 }
  );
  const rows = resp.data || [];
  all = all.concat(rows);
  if (rows.length < PAGE_SIZE) break;
  offset += PAGE_SIZE;
}
return all.map(r => ({
  json: {
    order_id: r.order_id,
    Appointment_Date: r.appointment_at,
    Final_Sale_Price: Number(r.final_sale_price) || 0,
    Total_Cost: Number(r.total_cost) || 0,
    Net_Profit: Number(r.net_profit) || 0
  }
}));

const axios = require('axios');
const SUPABASE_URL = 'https://vpmwizzixnwilmzctdvu.supabase.co';
const SUPABASE_KEY = (typeof process !== 'undefined' && process.env && process.env.SUPABASE_SERVICE_KEY) || 'sb_secret_EXq938yU-MinIxdpOc0nZg_qL-N3BCq';
const PAGE_SIZE = 1000;

const mainOrders = $('Collect Main Orders').first().json.mainOrders || [];
const orderIds = mainOrders.map(o => o.order_id).filter(Boolean);

if (orderIds.length === 0) {
  return [];
}

const idList = orderIds.map(id => `"${id}"`).join(',');
let all = [];
let offset = 0;
while (true) {
  const resp = await axios.get(
    `${SUPABASE_URL}/rest/v1/order_items?select=product_sku,quantity&order_fhs_id=in.(${idList})&order=id.asc&limit=${PAGE_SIZE}&offset=${offset}`,
    { headers: { apikey: SUPABASE_KEY, Authorization: `Bearer ${SUPABASE_KEY}` }, timeout: 15000 }
  );
  const rows = resp.data || [];
  all = all.concat(rows);
  if (rows.length < PAGE_SIZE) break;
  offset += PAGE_SIZE;
}
return all.map(r => ({
  json: {
    Product_Link: r.product_sku,
    Quantity: r.quantity
  }
}));
